/**
 * Patient Dashboard Component
 * Dashboard for patient users
 */

import React, { useState, useEffect, useRef } from "react";
import {
  Calendar,
  Pill,
  Activity,
  Clock,
  ChevronRight,
  TrendingUp,
  AlertCircle,
  Video,
  MessageSquare,
  User,
  Stethoscope,
  Send,
  Plus,
  Edit2,
  Trash2,
  Check,
  X,
} from "lucide-react";
import DashboardHeader from "../components/common/DashboardHeader";
import {
  medicationsAPI,
  appointmentsAPI,
  symptomsAPI,
  usersAPI,
  queueAPI,
} from "../services/api";

const PatientDashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState("overview");
  const [symptomText, setSymptomText] = useState("");
  const [medications, setMedications] = useState([]);
  const [appointments, setAppointments] = useState([]);
  const [doctors, setDoctors] = useState([]);
  const [myConsultations, setMyConsultations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [symptomAnalysis, setSymptomAnalysis] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);

  // Consultation booking state
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [consultationForm, setConsultationForm] = useState({
    condition: "",
    symptoms: "",
    symptomDuration: "",
    urgency: "medium",
    consultationType: "general",
    consultationMode: "video",
  });
  const [bookingLoading, setBookingLoading] = useState(false);
  const [bookingSuccess, setBookingSuccess] = useState(false);

  // Medication tracker state
  const [showAddMedForm, setShowAddMedForm] = useState(false);
  const [editingMed, setEditingMed] = useState(null);
  const [medForm, setMedForm] = useState({
    medicineName: "",
    dailyDosage: 1,
    totalQuantity: 30,
    remainingStock: 30,
    refillThreshold: 5,
    notes: "",
  });
  const [medLoading, setMedLoading] = useState(false);

  // Section refs for smooth scrolling
  const overviewRef = useRef(null);
  const consultRef = useRef(null);
  const symptomsRef = useRef(null);
  const appointmentsRef = useRef(null);
  const medicationsRef = useRef(null);
  const contentRef = useRef(null); // Ref for tab content container
  const addMedFormRef = useRef(null); // Ref for add medication form

  const sectionRefs = {
    overview: overviewRef,
    consult: consultRef,
    symptoms: symptomsRef,
    appointments: appointmentsRef,
    medications: medicationsRef,
  };

  // Handle tab click with smooth scroll
  const handleTabClick = (tab) => {
    setActiveTab(tab);
    // Scroll to content area after tab change
    setTimeout(() => {
      if (contentRef.current) {
        const yOffset = -20; // Small offset from top
        const y =
          contentRef.current.getBoundingClientRect().top +
          window.pageYOffset +
          yOffset;
        window.scrollTo({ top: y, behavior: "smooth" });
      }
    }, 50);
  };

  // Calculate stats
  const adherenceRate = 87; // This would be calculated from medication tracking data
  const activePrescriptions = medications.length;

  // Find next refill
  const getNextRefillDays = () => {
    const medsNeedingRefill = medications.filter((m) => m.needsRefill);
    if (medsNeedingRefill.length > 0) {
      return Math.min(...medsNeedingRefill.map((m) => m.daysRemaining));
    }
    return medications.length > 0
      ? Math.min(...medications.map((m) => m.daysRemaining))
      : 0;
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [medsRes, apptsRes, doctorsRes, consultRes] = await Promise.all([
        medicationsAPI.getAll(),
        appointmentsAPI.getAll({ upcoming: "true" }),
        usersAPI.getDoctors(),
        queueAPI.getMyConsultations
          ? queueAPI.getMyConsultations()
          : Promise.resolve({ success: true, data: [] }),
      ]);

      if (medsRes.success) setMedications(medsRes.data);
      if (apptsRes.success) setAppointments(apptsRes.data);
      if (doctorsRes.success) setDoctors(doctorsRes.data);
      if (consultRes.success) setMyConsultations(consultRes.data);
    } catch (error) {
      console.error("Error fetching data:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleBookConsultation = async () => {
    if (!selectedDoctor || !consultationForm.condition.trim()) return;

    try {
      setBookingLoading(true);
      const response = await queueAPI.joinQueue({
        doctorId: selectedDoctor._id,
        ...consultationForm,
      });

      if (response.success) {
        setBookingSuccess(true);
        setConsultationForm({
          condition: "",
          symptoms: "",
          symptomDuration: "",
          urgency: "medium",
          consultationType: "general",
          consultationMode: "video",
        });
        setSelectedDoctor(null);
        fetchData();

        setTimeout(() => setBookingSuccess(false), 3000);
      }
    } catch (error) {
      console.error("Error booking consultation:", error);
      alert(error.response?.data?.message || "Failed to book consultation");
    } finally {
      setBookingLoading(false);
    }
  };

  // Medication CRUD handlers
  const handleAddMedication = async () => {
    if (!medForm.medicineName.trim()) return;
    try {
      setMedLoading(true);
      const response = await medicationsAPI.create(medForm);
      if (response.success) {
        setMedications([...medications, response.data]);
        setMedForm({
          medicineName: "",
          dailyDosage: 1,
          totalQuantity: 30,
          remainingStock: 30,
          refillThreshold: 5,
          notes: "",
        });
        setShowAddMedForm(false);
      }
    } catch (error) {
      console.error("Error adding medication:", error);
      alert(error.response?.data?.message || "Failed to add medication");
    } finally {
      setMedLoading(false);
    }
  };

  const handleUpdateMedication = async () => {
    if (!editingMed || !medForm.medicineName.trim()) return;
    try {
      setMedLoading(true);
      const response = await medicationsAPI.update(editingMed._id, medForm);
      if (response.success) {
        setMedications(
          medications.map((m) =>
            m._id === editingMed._id ? response.data : m,
          ),
        );
        setEditingMed(null);
        setMedForm({
          medicineName: "",
          dailyDosage: 1,
          totalQuantity: 30,
          remainingStock: 30,
          refillThreshold: 5,
          notes: "",
        });
      }
    } catch (error) {
      console.error("Error updating medication:", error);
      alert(error.response?.data?.message || "Failed to update medication");
    } finally {
      setMedLoading(false);
    }
  };

  const handleDeleteMedication = async (medId) => {
    if (!window.confirm("Are you sure you want to delete this medication?"))
      return;
    try {
      const response = await medicationsAPI.delete(medId);
      if (response.success) {
        setMedications(medications.filter((m) => m._id !== medId));
      }
    } catch (error) {
      console.error("Error deleting medication:", error);
      alert(error.response?.data?.message || "Failed to delete medication");
    }
  };

  const startEditMedication = (med) => {
    setEditingMed(med);
    setMedForm({
      medicineName: med.medicineName,
      dailyDosage: med.dailyDosage,
      totalQuantity: med.totalQuantity,
      remainingStock: med.remainingStock,
      refillThreshold: med.refillThreshold || 5,
      notes: med.notes || "",
    });
    setShowAddMedForm(false);
  };

  const cancelMedForm = () => {
    setShowAddMedForm(false);
    setEditingMed(null);
    setMedForm({
      medicineName: "",
      dailyDosage: 1,
      totalQuantity: 30,
      remainingStock: 30,
      refillThreshold: 5,
      notes: "",
    });
  };

  const handleAnalyzeSymptoms = async () => {
    if (!symptomText.trim()) return;

    try {
      setAnalyzing(true);
      const response = await symptomsAPI.analyze(symptomText);
      if (response.success) {
        setSymptomAnalysis(response.data.analysis);
      }
    } catch (error) {
      console.error("Error analyzing symptoms:", error);
    } finally {
      setAnalyzing(false);
    }
  };

  const nextRefillDays = getNextRefillDays();

  return (
    <div className="min-h-screen bg-gray-50">
      <DashboardHeader user={user} onLogout={onLogout} />

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Welcome Section */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Welcome back, {user?.name?.split(" ")[0] || "Patient"}!
          </h1>
          <p className="text-gray-600">
            Here's your health overview for today.
          </p>
        </div>
        {/* Stats Row */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          <div className="bg-white rounded-2xl p-6 shadow-md">
            <div className="flex items-center justify-between mb-4">
              <div className="w-12 h-12 bg-teal-100 rounded-xl flex items-center justify-center">
                <TrendingUp className="w-6 h-6 text-teal-600" />
              </div>
              <span className="text-2xl font-bold text-teal-600">
                {adherenceRate}%
              </span>
            </div>
            <h3 className="font-semibold text-gray-900 mb-1">Adherence Rate</h3>
            <p className="text-sm text-gray-500">Great job this week!</p>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-md">
            <div className="flex items-center justify-between mb-4">
              <div className="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center">
                <Calendar className="w-6 h-6 text-blue-600" />
              </div>
              <span className="text-2xl font-bold text-blue-600">
                {nextRefillDays}d
              </span>
            </div>
            <h3 className="font-semibold text-gray-900 mb-1">Next Refill</h3>
            <p className="text-sm text-gray-500">
              {medications.find((m) => m.needsRefill)?.medicineName ||
                "All stocked"}
            </p>
          </div>

          <div className="bg-white rounded-2xl p-6 shadow-md">
            <div className="flex items-center justify-between mb-4">
              <div className="w-12 h-12 bg-purple-100 rounded-xl flex items-center justify-center">
                <Pill className="w-6 h-6 text-purple-600" />
              </div>
              <span className="text-2xl font-bold text-purple-600">
                {activePrescriptions}
              </span>
            </div>
            <h3 className="font-semibold text-gray-900 mb-1">
              Active Prescriptions
            </h3>
            <p className="text-sm text-gray-500">All medications tracked</p>
          </div>
        </div>
        {/* Tabs with smooth scroll - Sticky */}
        <div className="sticky top-0 z-10 bg-gray-50 py-4 -mx-4 px-4 sm:-mx-6 sm:px-6 lg:-mx-8 lg:px-8">
          <div className="flex space-x-2 overflow-x-auto pb-2 scrollbar-hide">
            {[
              { id: "overview", label: "Overview", icon: Activity },
              { id: "medications", label: "My Medications", icon: Pill },
              { id: "consult", label: "Book Consultation", icon: Stethoscope },
              { id: "symptoms", label: "Symptoms", icon: AlertCircle },
              { id: "appointments", label: "Appointments", icon: Calendar },
            ].map((tab) => {
              const Icon = tab.icon;
              return (
                <button
                  key={tab.id}
                  onClick={() => handleTabClick(tab.id)}
                  className={`px-5 py-3 rounded-xl font-medium transition whitespace-nowrap flex items-center space-x-2 ${
                    activeTab === tab.id
                      ? "bg-gradient-to-r from-teal-600 to-emerald-600 text-white shadow-lg shadow-teal-200"
                      : "bg-white text-gray-600 hover:bg-gray-50 shadow-sm"
                  }`}
                >
                  <Icon className="w-4 h-4" />
                  <span>{tab.label}</span>
                </button>
              );
            })}
          </div>
        </div>
        {/* Tab Content Container */}
        <div ref={contentRef} className="mt-2">
          {/* Overview Tab */}
          {activeTab === "overview" && (
            <div ref={overviewRef} className="space-y-6">
              <div className="bg-white rounded-2xl p-6 shadow-md">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-xl font-bold text-gray-900">
                    My Medications
                  </h2>
                  <button
                    onClick={() => handleTabClick("medications")}
                    className="text-teal-600 hover:text-teal-700 font-medium text-sm flex items-center"
                  >
                    View All <ChevronRight className="w-4 h-4 ml-1" />
                  </button>
                </div>

                {loading ? (
                  <div className="text-center py-8 text-gray-500">
                    Loading medications...
                  </div>
                ) : medications.length === 0 ? (
                  <div className="text-center py-8 text-gray-500">
                    <Pill className="w-12 h-12 mx-auto mb-3 text-gray-400" />
                    <p>No medications added yet</p>
                    <button
                      onClick={() => {
                        handleTabClick("medications");
                        setTimeout(() => setShowAddMedForm(true), 300);
                      }}
                      className="mt-3 text-teal-600 hover:text-teal-700 font-medium"
                    >
                      + Add Your First Medication
                    </button>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {medications.slice(0, 4).map((med) => {
                      const stockPercent =
                        (med.remainingStock / med.totalQuantity) * 100;
                      const isLow = med.needsRefill;

                      return (
                        <div
                          key={med._id}
                          className="border border-gray-200 rounded-xl p-4 hover:border-teal-300 transition"
                        >
                          <div className="flex items-start justify-between mb-3">
                            <div>
                              <h3 className="font-semibold text-gray-900">
                                {med.medicineName}
                              </h3>
                              <p className="text-sm text-gray-500">
                                {med.dailyDosage}x daily
                              </p>
                            </div>
                            <div
                              className={`px-3 py-1.5 rounded-full text-sm font-bold ${
                                isLow
                                  ? "bg-red-100 text-red-700 border-2 border-red-300"
                                  : "bg-emerald-100 text-emerald-700 border-2 border-emerald-300"
                              }`}
                            >
                              {med.remainingStock} left
                            </div>
                          </div>
                          <div className="space-y-3">
                            <div className="flex items-center justify-between">
                              <span className="text-sm font-medium text-gray-700">
                                Stock Level
                              </span>
                              <span
                                className={`text-lg font-bold ${isLow ? "text-red-600" : "text-emerald-600"}`}
                              >
                                {med.remainingStock} / {med.totalQuantity}
                              </span>
                            </div>
                            <div className="w-full bg-gray-300 rounded-full h-4 overflow-hidden shadow-inner">
                              <div
                                className={`h-full rounded-full transition-all ${
                                  isLow
                                    ? "bg-gradient-to-r from-red-600 to-orange-500"
                                    : "bg-gradient-to-r from-emerald-500 to-green-400"
                                }`}
                                style={{
                                  width: `${Math.min(stockPercent, 100)}%`,
                                }}
                              ></div>
                            </div>
                            <div className="flex items-center space-x-2 text-sm text-gray-600">
                              <Clock className="w-3 h-3" />
                              <span className="font-medium">
                                {med.daysRemaining} days remaining
                              </span>
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Medications Tab - Full Medicine Tracker */}
          {activeTab === "medications" && (
            <div ref={medicationsRef} className="space-y-6 scroll-mt-6">
              {/* Header with Add Button */}
              <div className="bg-gradient-to-r from-teal-600 to-emerald-600 rounded-2xl p-6 shadow-lg">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                  <div className="text-white">
                    <h2 className="text-2xl font-bold mb-1">
                      Medicine Tracker
                    </h2>
                    <p className="text-teal-100">
                      Track and manage all your medications in one place
                    </p>
                  </div>
                  <button
                    onClick={() => {
                      setShowAddMedForm(true);
                      setEditingMed(null);
                      // Auto scroll to form after it renders
                      setTimeout(() => {
                        if (addMedFormRef.current) {
                          addMedFormRef.current.scrollIntoView({
                            behavior: "smooth",
                            block: "start",
                          });
                        }
                      }, 100);
                    }}
                    className="flex items-center justify-center space-x-2 bg-white text-teal-600 px-5 py-3 rounded-xl font-semibold hover:bg-teal-50 transition shadow-md"
                  >
                    <Plus className="w-5 h-5" />
                    <span>Add Medication</span>
                  </button>
                </div>
              </div>

              {/* Add/Edit Form */}
              {(showAddMedForm || editingMed) && (
                <div ref={addMedFormRef} className="bg-white rounded-2xl p-6 shadow-md border-2 border-teal-100 scroll-mt-6">
                  <div className="flex items-center justify-between mb-6">
                    <h3 className="text-lg font-bold text-gray-900">
                      {editingMed ? "Edit Medication" : "Add New Medication"}
                    </h3>
                    <button
                      onClick={cancelMedForm}
                      className="p-2 text-gray-400 hover:text-gray-600 rounded-lg hover:bg-gray-100 transition"
                    >
                      <X className="w-5 h-5" />
                    </button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    <div className="md:col-span-2 lg:col-span-1">
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Medicine Name *
                      </label>
                      <input
                        type="text"
                        value={medForm.medicineName}
                        onChange={(e) =>
                          setMedForm({
                            ...medForm,
                            medicineName: e.target.value,
                          })
                        }
                        placeholder="e.g., Aspirin, Metformin"
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Daily Dosage
                      </label>
                      <input
                        type="number"
                        min="1"
                        value={medForm.dailyDosage}
                        onChange={(e) =>
                          setMedForm({
                            ...medForm,
                            dailyDosage: parseInt(e.target.value) || 1,
                          })
                        }
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Total Quantity
                      </label>
                      <input
                        type="number"
                        min="1"
                        value={medForm.totalQuantity}
                        onChange={(e) =>
                          setMedForm({
                            ...medForm,
                            totalQuantity: parseInt(e.target.value) || 1,
                          })
                        }
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Remaining Stock
                      </label>
                      <input
                        type="number"
                        min="0"
                        value={medForm.remainingStock}
                        onChange={(e) =>
                          setMedForm({
                            ...medForm,
                            remainingStock: parseInt(e.target.value) || 0,
                          })
                        }
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Refill Alert (days)
                      </label>
                      <input
                        type="number"
                        min="1"
                        value={medForm.refillThreshold}
                        onChange={(e) =>
                          setMedForm({
                            ...medForm,
                            refillThreshold: parseInt(e.target.value) || 5,
                          })
                        }
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent"
                      />
                    </div>

                    <div className="md:col-span-2 lg:col-span-3">
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Notes (optional)
                      </label>
                      <textarea
                        value={medForm.notes}
                        onChange={(e) =>
                          setMedForm({ ...medForm, notes: e.target.value })
                        }
                        placeholder="Add any notes about this medication..."
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent h-20 resize-none"
                      />
                    </div>
                  </div>

                  <div className="flex justify-end space-x-3 mt-6">
                    <button
                      onClick={cancelMedForm}
                      className="px-6 py-3 bg-gray-100 text-gray-700 rounded-xl font-medium hover:bg-gray-200 transition"
                    >
                      Cancel
                    </button>
                    <button
                      onClick={
                        editingMed
                          ? handleUpdateMedication
                          : handleAddMedication
                      }
                      disabled={medLoading || !medForm.medicineName.trim()}
                      className="px-6 py-3 bg-gradient-to-r from-teal-600 to-emerald-600 text-white rounded-xl font-semibold hover:from-teal-700 hover:to-emerald-700 transition flex items-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                      {medLoading ? (
                        <>
                          <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                          <span>Saving...</span>
                        </>
                      ) : (
                        <>
                          <Check className="w-5 h-5" />
                          <span>
                            {editingMed ? "Update" : "Add"} Medication
                          </span>
                        </>
                      )}
                    </button>
                  </div>
                </div>
              )}

              {/* Medications List */}
              <div className="bg-white rounded-2xl shadow-md overflow-hidden">
                <div className="p-6 border-b border-gray-100">
                  <div className="flex items-center justify-between">
                    <div>
                      <h3 className="text-lg font-bold text-gray-900">
                        Your Medications
                      </h3>
                      <p className="text-sm text-gray-500">
                        {medications.length} medication
                        {medications.length !== 1 ? "s" : ""} tracked
                      </p>
                    </div>
                    <div className="flex items-center space-x-2 text-sm">
                      <span className="flex items-center text-green-600">
                        <span className="w-3 h-3 bg-green-500 rounded-full mr-2"></span>
                        Stocked
                      </span>
                      <span className="flex items-center text-rose-600 ml-4">
                        <span className="w-3 h-3 bg-rose-500 rounded-full mr-2"></span>
                        Low
                      </span>
                    </div>
                  </div>
                </div>

                {loading ? (
                  <div className="text-center py-12 text-gray-500">
                    <div className="w-8 h-8 border-4 border-teal-500 border-t-transparent rounded-full animate-spin mx-auto mb-3"></div>
                    Loading medications...
                  </div>
                ) : medications.length === 0 ? (
                  <div className="text-center py-12 text-gray-500">
                    <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                      <Pill className="w-10 h-10 text-gray-400" />
                    </div>
                    <p className="text-lg font-medium text-gray-700 mb-2">
                      No medications yet
                    </p>
                    <p className="text-gray-500 mb-4">
                      Start tracking your medications to never miss a dose
                    </p>
                    <button
                      onClick={() => setShowAddMedForm(true)}
                      className="inline-flex items-center space-x-2 text-teal-600 hover:text-teal-700 font-medium"
                    >
                      <Plus className="w-5 h-5" />
                      <span>Add Your First Medication</span>
                    </button>
                  </div>
                ) : (
                  <div className="divide-y divide-gray-100">
                    {medications.map((med) => {
                      const stockPercent =
                        (med.remainingStock / med.totalQuantity) * 100;
                      const isLow = med.needsRefill;

                      return (
                        <div
                          key={med._id}
                          className="p-6 hover:bg-gray-50 transition group"
                        >
                          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
                            {/* Med Info */}
                            <div className="flex items-start space-x-4">
                              <div
                                className={`w-16 h-16 rounded-xl flex items-center justify-center shadow-md ${
                                  isLow
                                    ? "bg-gradient-to-br from-red-500 to-orange-500"
                                    : "bg-gradient-to-br from-emerald-500 to-green-500"
                                }`}
                              >
                                <Pill className="w-8 h-8 text-white" />
                              </div>
                              <div>
                                <h4 className="font-bold text-gray-900 text-xl">
                                  {med.medicineName}
                                </h4>
                                <p className="text-base text-gray-600 mt-1">
                                  {med.dailyDosage}x daily • {med.daysRemaining}{" "}
                                  days remaining
                                </p>
                                {med.notes && (
                                  <p className="text-sm text-gray-400 mt-1 line-clamp-1">
                                    {med.notes}
                                  </p>
                                )}
                              </div>
                            </div>

                            {/* Stock Bar */}
                            <div className="flex-1 max-w-sm">
                              <div className="flex items-center justify-between mb-3">
                                <span className="text-base font-medium text-gray-700">
                                  Stock Level
                                </span>
                                <span
                                  className={`text-xl font-bold ${isLow ? "text-red-600" : "text-emerald-600"}`}
                                >
                                  {med.remainingStock} / {med.totalQuantity}
                                </span>
                              </div>
                              <div className="w-full bg-gray-300 rounded-full h-5 overflow-hidden shadow-inner">
                                <div
                                  className={`h-full rounded-full transition-all duration-500 ${
                                    isLow
                                      ? "bg-gradient-to-r from-red-600 to-orange-500"
                                      : "bg-gradient-to-r from-emerald-500 to-green-400"
                                  }`}
                                  style={{
                                    width: `${Math.min(stockPercent, 100)}%`,
                                  }}
                                ></div>
                              </div>
                              <div className="flex items-center justify-between mt-2">
                                <span
                                  className={`text-sm font-semibold ${isLow ? "text-red-600" : "text-emerald-600"}`}
                                >
                                  {Math.round(stockPercent)}% remaining
                                </span>
                                <span className="text-sm font-medium text-gray-600">
                                  {med.daysRemaining} days left
                                </span>
                              </div>
                            </div>

                            {/* Actions */}
                            <div className="flex items-center space-x-2 lg:opacity-0 lg:group-hover:opacity-100 transition">
                              <button
                                onClick={() => startEditMedication(med)}
                                className="p-2 text-gray-400 hover:text-teal-600 hover:bg-teal-50 rounded-lg transition"
                                title="Edit"
                              >
                                <Edit2 className="w-5 h-5" />
                              </button>
                              <button
                                onClick={() => handleDeleteMedication(med._id)}
                                className="p-2 text-gray-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition"
                                title="Delete"
                              >
                                <Trash2 className="w-5 h-5" />
                              </button>
                            </div>
                          </div>

                          {/* Low Stock Alert */}
                          {isLow && (
                            <div className="mt-4 flex items-center space-x-3 text-red-700 bg-red-100 border-2 border-red-300 px-4 py-3 rounded-xl animate-pulse">
                              <AlertCircle className="w-6 h-6" />
                              <span className="text-base font-bold">
                                ⚠️ Low stock - Refill soon!
                              </span>
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            </div>
          )}

          {/* Consult Tab - Book Consultation with Doctors */}
          {activeTab === "consult" && (
            <div ref={consultRef} className="space-y-6 scroll-mt-6">
              {/* Success Message */}
              {bookingSuccess && (
                <div className="bg-green-50 border border-green-200 rounded-xl p-4 flex items-center">
                  <svg
                    className="w-5 h-5 text-green-600 mr-3"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M5 13l4 4L19 7"
                    />
                  </svg>
                  <span className="text-green-700">
                    Consultation request submitted successfully! The doctor will
                    attend to you soon.
                  </span>
                </div>
              )}

              {/* Available Doctors */}
              <div className="bg-white rounded-2xl p-6 shadow-md">
                <h2 className="text-xl font-bold text-gray-900 mb-2">
                  Available Doctors
                </h2>
                <p className="text-gray-600 mb-6">
                  Select a doctor to book a consultation
                </p>

                {loading ? (
                  <div className="text-center py-8 text-gray-500">
                    Loading doctors...
                  </div>
                ) : doctors.length === 0 ? (
                  <div className="text-center py-8 text-gray-500">
                    <Stethoscope className="w-12 h-12 mx-auto mb-3 text-gray-400" />
                    <p>No doctors available at the moment</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {doctors.map((doctor) => (
                      <div
                        key={doctor._id}
                        onClick={() => setSelectedDoctor(doctor)}
                        className={`p-4 rounded-xl border-2 cursor-pointer transition ${
                          selectedDoctor?._id === doctor._id
                            ? "border-teal-500 bg-teal-50"
                            : "border-gray-200 hover:border-teal-300"
                        }`}
                      >
                        <div className="flex items-center space-x-3">
                          <div
                            className="w-12 h-12 rounded-full flex items-center justify-center text-white font-bold"
                            style={{
                              backgroundColor: doctor.avatarColor || "#3B82F6",
                            }}
                          >
                            {doctor.name.charAt(0).toUpperCase()}
                          </div>
                          <div>
                            <h3 className="font-semibold text-gray-900">
                              {doctor.name}
                            </h3>
                            <p className="text-sm text-teal-600">
                              {doctor.specialty || "General Physician"}
                            </p>
                            {doctor.experience && (
                              <p className="text-xs text-gray-500">
                                {doctor.experience} years exp.
                              </p>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Consultation Form - Shows when doctor is selected */}
              {selectedDoctor && (
                <div className="bg-white rounded-2xl p-6 shadow-md">
                  <div className="flex items-center justify-between mb-6">
                    <div>
                      <h2 className="text-xl font-bold text-gray-900">
                        Book Consultation
                      </h2>
                      <p className="text-gray-600">
                        with Dr. {selectedDoctor.name} (
                        {selectedDoctor.specialty || "General"})
                      </p>
                    </div>
                    <button
                      onClick={() => setSelectedDoctor(null)}
                      className="text-gray-400 hover:text-gray-600"
                    >
                      <svg
                        className="w-6 h-6"
                        fill="none"
                        viewBox="0 0 24 24"
                        stroke="currentColor"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={2}
                          d="M6 18L18 6M6 6l12 12"
                        />
                      </svg>
                    </button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="md:col-span-2">
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Main Concern / Condition *
                      </label>
                      <input
                        type="text"
                        value={consultationForm.condition}
                        onChange={(e) =>
                          setConsultationForm({
                            ...consultationForm,
                            condition: e.target.value,
                          })
                        }
                        placeholder="e.g., Persistent headache, Skin rash, Fever"
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500"
                      />
                    </div>

                    <div className="md:col-span-2">
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Describe Your Symptoms
                      </label>
                      <textarea
                        value={consultationForm.symptoms}
                        onChange={(e) =>
                          setConsultationForm({
                            ...consultationForm,
                            symptoms: e.target.value,
                          })
                        }
                        placeholder="Describe your symptoms in detail..."
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 h-24 resize-none"
                      />
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        How long have you had these symptoms?
                      </label>
                      <select
                        value={consultationForm.symptomDuration}
                        onChange={(e) =>
                          setConsultationForm({
                            ...consultationForm,
                            symptomDuration: e.target.value,
                          })
                        }
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500"
                      >
                        <option value="">Select duration</option>
                        <option value="Less than 24 hours">
                          Less than 24 hours
                        </option>
                        <option value="1-3 days">1-3 days</option>
                        <option value="4-7 days">4-7 days</option>
                        <option value="1-2 weeks">1-2 weeks</option>
                        <option value="More than 2 weeks">
                          More than 2 weeks
                        </option>
                      </select>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Urgency Level
                      </label>
                      <select
                        value={consultationForm.urgency}
                        onChange={(e) =>
                          setConsultationForm({
                            ...consultationForm,
                            urgency: e.target.value,
                          })
                        }
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500"
                      >
                        <option value="low">Low - General checkup</option>
                        <option value="medium">Medium - Some discomfort</option>
                        <option value="high">
                          High - Significant pain/concern
                        </option>
                        <option value="critical">Critical - Emergency</option>
                      </select>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Consultation Type
                      </label>
                      <select
                        value={consultationForm.consultationType}
                        onChange={(e) =>
                          setConsultationForm({
                            ...consultationForm,
                            consultationType: e.target.value,
                          })
                        }
                        className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500"
                      >
                        <option value="general">General Consultation</option>
                        <option value="follow-up">Follow-up Visit</option>
                        <option value="specialist">
                          Specialist Consultation
                        </option>
                        <option value="emergency">Emergency</option>
                      </select>
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Preferred Mode
                      </label>
                      <div className="flex space-x-3">
                        {[
                          { value: "video", icon: Video, label: "Video" },
                          { value: "chat", icon: MessageSquare, label: "Chat" },
                        ].map((mode) => (
                          <button
                            key={mode.value}
                            type="button"
                            onClick={() =>
                              setConsultationForm({
                                ...consultationForm,
                                consultationMode: mode.value,
                              })
                            }
                            className={`flex-1 flex items-center justify-center space-x-2 py-3 rounded-xl border-2 transition ${
                              consultationForm.consultationMode === mode.value
                                ? "border-teal-500 bg-teal-50 text-teal-700"
                                : "border-gray-200 text-gray-600 hover:border-teal-300"
                            }`}
                          >
                            <mode.icon className="w-5 h-5" />
                            <span>{mode.label}</span>
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>

                  <button
                    onClick={handleBookConsultation}
                    disabled={
                      bookingLoading || !consultationForm.condition.trim()
                    }
                    className="w-full mt-6 bg-teal-600 text-white py-4 rounded-xl hover:bg-teal-700 transition font-semibold flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <Send className="w-5 h-5 mr-2" />
                    {bookingLoading
                      ? "Submitting..."
                      : "Submit Consultation Request"}
                  </button>
                </div>
              )}
            </div>
          )}

          {/* Symptoms Tab */}
          {activeTab === "symptoms" && (
            <div
              ref={symptomsRef}
              className="bg-white rounded-2xl p-6 shadow-md scroll-mt-6"
            >
              <h2 className="text-xl font-bold text-gray-900 mb-4">
                Symptom Checker
              </h2>
              <p className="text-gray-600 mb-6">
                Describe your symptoms and get AI-powered health insights.
              </p>

              <div className="space-y-4">
                <textarea
                  value={symptomText}
                  onChange={(e) => setSymptomText(e.target.value)}
                  placeholder="Example: I've been experiencing headaches and mild fever for the past 2 days..."
                  className="w-full h-40 px-4 py-3 border border-gray-300 rounded-xl focus:outline-none focus:ring-2 focus:ring-teal-500 focus:border-transparent resize-none"
                />

                <div className="flex flex-col sm:flex-row gap-3">
                  <button
                    onClick={handleAnalyzeSymptoms}
                    disabled={analyzing || !symptomText.trim()}
                    className="flex-1 bg-teal-600 text-white py-3 px-6 rounded-xl hover:bg-teal-700 transition font-semibold flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <Activity className="w-5 h-5 mr-2" />
                    {analyzing ? "Analyzing..." : "Analyze Symptoms"}
                  </button>
                  <button
                    onClick={() => {
                      setSymptomText("");
                      setSymptomAnalysis(null);
                    }}
                    className="sm:w-auto bg-gray-100 text-gray-700 py-3 px-6 rounded-xl hover:bg-gray-200 transition font-semibold"
                  >
                    Clear
                  </button>
                </div>

                {symptomAnalysis && (
                  <div className="mt-6 p-4 bg-gray-50 rounded-xl space-y-4">
                    <h3 className="font-semibold text-gray-900">
                      Analysis Results
                    </h3>

                    {symptomAnalysis.possibleConditions?.length > 0 && (
                      <div>
                        <p className="text-sm font-medium text-gray-700 mb-2">
                          Possible Conditions:
                        </p>
                        <ul className="space-y-2">
                          {symptomAnalysis.possibleConditions.map(
                            (condition, idx) => (
                              <li
                                key={idx}
                                className="text-sm text-gray-600 flex items-center"
                              >
                                <span className="w-2 h-2 bg-teal-500 rounded-full mr-2"></span>
                                {condition.name} ({condition.probability}%)
                              </li>
                            ),
                          )}
                        </ul>
                      </div>
                    )}

                    {symptomAnalysis.recommendations?.length > 0 && (
                      <div>
                        <p className="text-sm font-medium text-gray-700 mb-2">
                          Recommendations:
                        </p>
                        <ul className="space-y-1">
                          {symptomAnalysis.recommendations.map((rec, idx) => (
                            <li key={idx} className="text-sm text-gray-600">
                              • {rec}
                            </li>
                          ))}
                        </ul>
                      </div>
                    )}

                    <div
                      className={`text-sm px-3 py-2 rounded-lg ${
                        symptomAnalysis.urgencyLevel === "high" ||
                        symptomAnalysis.urgencyLevel === "emergency"
                          ? "bg-rose-100 text-rose-700"
                          : "bg-blue-100 text-blue-700"
                      }`}
                    >
                      Urgency Level:{" "}
                      <span className="font-medium capitalize">
                        {symptomAnalysis.urgencyLevel}
                      </span>
                    </div>
                  </div>
                )}

                <div className="bg-blue-50 border border-blue-200 rounded-xl p-4 flex items-start space-x-3">
                  <AlertCircle className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                  <div className="text-sm text-blue-800">
                    <p className="font-medium mb-1">
                      This is not medical advice
                    </p>
                    <p>
                      Symptom analysis is AI-powered and should not replace
                      professional medical consultation. For emergencies, call
                      911.
                    </p>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Appointments Tab */}
          {activeTab === "appointments" && (
            <div
              ref={appointmentsRef}
              className="space-y-6 scroll-mt-6"
            >
              {/* Available Doctors Section */}
              <div className="bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl p-6 shadow-lg">
                <div className="text-white mb-4">
                  <h2 className="text-2xl font-bold mb-1">Book an Appointment</h2>
                  <p className="text-blue-100">Choose a doctor and schedule your visit</p>
                </div>
              </div>

              {/* Doctors Grid */}
              <div className="bg-white rounded-2xl p-6 shadow-md">
                <h3 className="text-lg font-bold text-gray-900 mb-4">Available Doctors</h3>
                {loading ? (
                  <div className="text-center py-8 text-gray-500">
                    Loading doctors...
                  </div>
                ) : doctors.length === 0 ? (
                  <div className="text-center py-8 text-gray-500">
                    <Stethoscope className="w-12 h-12 mx-auto mb-3 text-gray-400" />
                    <p>No doctors available at the moment</p>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {doctors.map((doctor) => (
                      <div
                        key={doctor._id}
                        className="border-2 border-gray-200 rounded-xl p-5 hover:border-blue-400 hover:shadow-lg transition cursor-pointer group"
                        onClick={() => {
                          handleTabClick('consult');
                          setSelectedDoctor(doctor);
                        }}
                      >
                        <div className="flex items-center space-x-4">
                          <div
                            className="w-16 h-16 rounded-full flex items-center justify-center text-white text-xl font-bold shadow-md"
                            style={{
                              backgroundColor: doctor.avatarColor || "#3B82F6",
                            }}
                          >
                            {doctor.name.charAt(0).toUpperCase()}
                          </div>
                          <div className="flex-1">
                            <h4 className="font-bold text-gray-900 text-lg group-hover:text-blue-600 transition">
                              Dr. {doctor.name}
                            </h4>
                            <p className="text-blue-600 font-medium">
                              {doctor.specialty || "General Physician"}
                            </p>
                            {doctor.experience && (
                              <p className="text-sm text-gray-500 mt-1">
                                {doctor.experience} years experience
                              </p>
                            )}
                          </div>
                        </div>
                        <div className="mt-4 pt-4 border-t border-gray-100 flex items-center justify-between">
                          <div className="flex items-center space-x-2 text-gray-500 text-sm">
                            <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                            <span>Available</span>
                          </div>
                          <button className="px-4 py-2 bg-blue-50 text-blue-600 rounded-lg font-medium text-sm group-hover:bg-blue-600 group-hover:text-white transition">
                            Book Now
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Upcoming Appointments */}
              <div className="bg-white rounded-2xl p-6 shadow-md">
                <h3 className="text-lg font-bold text-gray-900 mb-4">Your Upcoming Appointments</h3>

              {loading ? (
                <div className="text-center py-8 text-gray-500">
                  Loading appointments...
                </div>
              ) : appointments.length === 0 ? (
                <div className="text-center py-8 text-gray-500">
                  <Calendar className="w-12 h-12 mx-auto mb-3 text-gray-400" />
                  <p>No upcoming appointments</p>
                  <p className="text-sm text-gray-400 mt-2">Select a doctor above to book your first appointment</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {appointments.map((appointment) => (
                    <div
                      key={appointment._id}
                      className="border border-gray-200 rounded-xl p-4 hover:border-blue-300 hover:shadow-md transition"
                    >
                      <div className="flex items-center justify-between mb-3">
                        <div className="flex items-center space-x-3">
                          <div
                            className="w-14 h-14 rounded-full flex items-center justify-center text-white font-bold"
                            style={{
                              backgroundColor:
                                appointment.doctorId?.avatarColor || "#3B82F6",
                            }}
                          >
                            {appointment.doctorId?.name?.charAt(0)?.toUpperCase() || "D"}
                          </div>
                          <div>
                            <h4 className="font-bold text-gray-900 text-lg">
                              Dr. {appointment.doctorId?.name}
                            </h4>
                            <p className="text-blue-600 font-medium">
                              {appointment.doctorId?.specialty || "General"}
                            </p>
                          </div>
                        </div>
                        <div className="flex items-center space-x-2">
                          {appointment.type === "video" && (
                            <button className="p-2.5 bg-blue-100 rounded-lg hover:bg-blue-200 transition">
                              <Video className="w-5 h-5 text-blue-600" />
                            </button>
                          )}
                          <button className="p-2.5 bg-teal-100 rounded-lg hover:bg-teal-200 transition">
                            <MessageSquare className="w-5 h-5 text-teal-600" />
                          </button>
                        </div>
                      </div>
                      <div className="flex items-center justify-between pt-3 border-t">
                        <div className="flex items-center space-x-2 text-gray-700">
                          <Calendar className="w-5 h-5 text-blue-600" />
                          <span className="font-medium">
                            {new Date(
                              appointment.scheduledAt,
                            ).toLocaleDateString("en-US", {
                              weekday: "short",
                              month: "short",
                              day: "numeric",
                              year: "numeric",
                              hour: "2-digit",
                              minute: "2-digit",
                            })}
                          </span>
                        </div>
                        {appointment.type === "video" && (
                          <button className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white px-5 py-2.5 rounded-lg hover:from-blue-700 hover:to-indigo-700 transition font-semibold shadow-md">
                            Join Call
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              )}
              </div>
            </div>
          )}
        </div>{" "}
        {/* End of content container */}
      </div>
    </div>
  );
};

export default PatientDashboard;
